const t = $('Execute Workflow Trigger').item.json;

const body = {
  type: 'VSphereBackup',
  name: t.jobName,
  description: t.jobDescription || 'Created by BackupPaw',
  virtualMachines: {
    includes: [{
      platform: 'VSphere',
      type: 'VirtualMachine',
      name: t.vmName,
      objectId: t.objectId,
      hostName: t.hostName
    }],
    excludes: {
      vms: [],
      disks: [],
      templates: { isEnabled: false, excludeFromIncremental: false }
    }
  },
  storage: {
    backupRepositoryId: t.repositoryId,
    backupProxies: { autoSelectEnabled: true, proxyIds: [] },
    retentionPolicy: {
      type: 'RestorePoints',
      quantity: parseInt(t.retentionPoints) || 7
    }
  },
  schedule: {
    daily: {
      dailyKind: 'Everyday',
      isEnabled: true,
      localTime: t.scheduleTime || '22:00',
      days: ['sunday','monday','tuesday','wednesday','thursday','friday','saturday']
    },
    monthly: { isEnabled: false, dayOfWeek: 'saturday', dayNumberInMonth: 'Fourth', localTime: '22:00', dayOfMonth: 1,
      months: ['January','February','March','April','May','June','July','August','September','October','November','December'] },
    periodically: { periodicallyKind: 'Hours', isEnabled: false, frequency: 0 },
    retry: { isEnabled: true, retryCount: 3, awaitMinutes: 10 },
    backupWindow: { isEnabled: false },
    runAutomatically: true
  }
};

return [{ json: { body: JSON.stringify(body) } }];
